//! GOLD-1 trajectory test (PLAN.md §14) — the normative serve-to-miss rally.
//!
//! Scenario: level 1, mouse pinned at the world center forever (paddle speed
//! ≡ 0), serve applied at tick 0. Reference values generated by the kit's
//! `golden_sim.py`; if this sim and those values disagree, this sim is wrong.
//!
//! One plan correction is baked in (see `DEVIATIONS.md` C1): the bonus drain
//! steps every **11** in-flight ticks (counter 10 → −1), so `bonusDisplay`
//! checkpoints land at f11 = 2975, f22 = 2950, f33 = 2925, … final 2675.

#![expect(
    clippy::expect_used,
    reason = "test assertions may unwrap scenario invariants"
)]

use curveball::consts::{WORLD_CX, WORLD_CY};
use curveball::sim::{CurveClass, SimEvent, SimInput, World, Zone};

/// Relative tolerance 1e-9 (the projection's `atan` may differ in the last
/// ulp across platforms). A zero expectation accepts either signed zero —
/// the signs that matter (Q10) are asserted bit-exactly at their ticks.
fn assert_rel(actual: f64, expected: f64, what: &str) {
    if expected == 0.0 {
        assert!(actual == 0.0, "{what}: {actual} != ±0.0");
        return;
    }
    let rel = ((actual - expected) / expected).abs();
    assert!(rel < 1e-9, "{what}: {actual} vs {expected} (rel {rel:e})");
}

/// (tick, x, y, z, vx, vy, cx, cy).
type TrajectoryRow = (u32, f64, f64, f64, f64, f64, f64, f64);

struct Harness {
    world: World,
    tick: u32,
    log: Vec<(u32, SimEvent)>,
}

impl Harness {
    /// Level-1 world in the Serve hold: enemy and ball on stage, every actor
    /// settled at the world center. Two warm-up ticks mirror Flash clip
    /// instantiation (no enterFrame on the placement frame) and let the ball
    /// cache the paddle snapshot the serve will read.
    fn new() -> Self {
        let mut world = World::new(curveball::sim::Published::default());
        world.level_setup();
        world.spawn_enemy();
        world.spawn_ball();
        let mut harness = Self {
            world,
            tick: 0,
            log: Vec::new(),
        };
        harness.run(0);
        harness.run(0);
        harness.tick = 0;
        harness.log.clear();
        harness
    }

    fn run(&mut self, clicks: u32) {
        self.tick += 1;
        let events = self.world.tick(&SimInput {
            mouse: (WORLD_CX, WORLD_CY),
            serve_clicks: clicks,
        });
        for event in events {
            self.log.push((self.tick, event));
        }
    }

    fn ball(&self) -> &curveball::sim::Ball {
        self.world
            .ball
            .as_ref()
            .expect("ball on stage for the whole scenario")
    }

    fn check_row(&self, row: &TrajectoryRow) {
        let (n, x, y, z, vx, vy, cx, cy) = *row;
        let ball = self.ball();
        assert_rel(ball.pos.x, x, &format!("f{n} x"));
        assert_rel(ball.pos.y, y, &format!("f{n} y"));
        assert_rel(ball.pos.z, z, &format!("f{n} z"));
        assert_rel(ball.vel.x, vx, &format!("f{n} vx"));
        assert_rel(ball.vel.y, vy, &format!("f{n} vy"));
        assert_rel(ball.curve.0, cx, &format!("f{n} cx"));
        assert_rel(ball.curve.1, cy, &format!("f{n} cy"));
    }
}

