/// (tick, bonusDisplay) — drains every 11 in-flight ticks.
const BONUS_CHECKPOINTS: [(u32, i32); 10] = [
    (10, 3000),
    (11, 2975),
    (22, 2950),
    (33, 2925),
    (37, 2925),
    (44, 2900),
    (76, 2850),
    (77, 2825),
    (114, 2750),
    (152, 2675),
];

/// (tick, enemy x, enemy y) — verifies the 1-tick publish lag and both
/// easing divisors (15 home, 17 chase at level 1).
const ENEMY_CHECKPOINTS: [(u32, f64, f64); 3] = [
    (2, 175.499_411_765, 125.500_588_235),
    (38, 172.231_734_731, 128.768_265_269),
    (114, 136.670_240_385, 164.329_759_615),
];

#[test]
fn gold1_trajectory() {
    let mut h = Harness::new();

    let mut trajectory = TRAJECTORY.iter().peekable();
    let mut bonuses = BONUS_CHECKPOINTS.iter().peekable();
    let mut enemies = ENEMY_CHECKPOINTS.iter().peekable();

    for tick in 1..=152 {
        h.run(u32::from(tick == 1));

        if tick == 1 {
            // Serve result: minimum-curve injection (−0.01, −0.01) from a
            // still paddle, observed after this tick's single decay step, and
            // the accuracy bonus for the centered ball.
            let ball = h.ball();
            let decayed_injection = -0.01_f64 / 1.004;
            assert_eq!(
                ball.curve.0.to_bits(),
                decayed_injection.to_bits(),
                "serve cx"
            );
            assert_eq!(
                ball.curve.1.to_bits(),
                decayed_injection.to_bits(),
                "serve cy"
            );
            assert_eq!(ball.vel.z.to_bits(), 2.0_f64.to_bits(), "serve vz");
            assert_eq!(h.world.economy.score, 100, "serve score");
            assert_eq!(h.world.economy.accuracy_bonus, 90, "serve accuracy degrade");
        }
        if tick == 76 {
            // Q10 signs: cx = −pSpeedX/25 = −0.0, cy = +pSpeedY/25 = +0.0;
            // the decay guard must then skip both.
            let ball = h.ball();
            assert_eq!(
                ball.curve.0.to_bits(),
                (-0.0_f64).to_bits(),
                "f76 cx is -0.0"
            );
            assert_eq!(ball.curve.1.to_bits(), 0.0_f64.to_bits(), "f76 cy is +0.0");
            assert_eq!(h.world.economy.score, 200, "f76 score");
            assert_eq!(h.world.economy.hit_score, 90, "f76 hitScore degrade");
            assert_eq!(h.world.economy.accuracy_bonus, 90, "f76 accuracy untouched");
        }

        if let Some(&&row) = trajectory.peek()
            && row.0 == tick
        {
            h.check_row(&row);
            trajectory.next();
        }
        if let Some(&&(n, expected)) = bonuses.peek()
            && n == tick
        {
            assert_eq!(h.world.economy.bonus_display, expected, "f{n} bonusDisplay");
            bonuses.next();
        }
        if let Some(&&(n, ex, ey)) = enemies.peek()
            && n == tick
        {
            assert_rel(
                h.world.enemy.as_ref().map_or(0.0, |e| e.pos.0),
                ex,
                "enemy x",
            );
            assert_rel(
                h.world.enemy.as_ref().map_or(0.0, |e| e.pos.1),
                ey,
                "enemy y",
            );
            enemies.next();
        }
    }
    assert!(trajectory.peek().is_none(), "all trajectory rows checked");
    assert!(bonuses.peek().is_none(), "all bonus checkpoints checked");
    assert!(enemies.peek().is_none(), "all enemy checkpoints checked");

    // Exact event log: order, ticks, payloads — and nothing else.
    let expected_events = [
        (
            1,
            SimEvent::Serve {
                zone: Zone::C,
                accuracy: true,
                curve: CurveClass::None,
            },
        ),
        (38, SimEvent::EnemyHit { zone: Zone::C }),
        (
            76,
            SimEvent::PlayerHit {
                zone: Zone::BL,
                accuracy: false,
                curve: CurveClass::None,
            },
        ),
        (114, SimEvent::EnemyHit { zone: Zone::BL }),
        (145, SimEvent::WallBounce { horizontal: false }),
        (152, SimEvent::PlayerMiss),
    ];
    assert_eq!(h.log, expected_events, "event log");

    // Post-miss state: lives, rally-bonus reset, bonusDisplay survival (Q8).
    assert_eq!(h.world.player_lives, 4);
    assert_eq!(h.world.economy.score, 200);
    assert_eq!(h.world.economy.hit_score, 100);
    assert_eq!(h.world.economy.curve_bonus, 50);
    assert_eq!(h.world.economy.super_curve_bonus, 150);
    assert_eq!(h.world.economy.accuracy_bonus, 100);
    assert_eq!(h.world.economy.bonus_display, 2675);
    let ball = h.ball();
    assert!(ball.stopped);
    assert_eq!(ball.vel.z.to_bits(), 0.0_f64.to_bits());
    assert_eq!(h.world.published.dir.z.to_bits(), 0.0_f64.to_bits());

    // One more tick: the ring pins to the published miss z clamped at 0
    // (player-side miss overshoots to z = −1 → ring shows full size).
    h.run(0);
    assert_eq!(h.world.ring_z.to_bits(), 0.0_f64.to_bits());
    assert_rel(h.world.published.pos.z, -1.0, "published miss z");
}
